// VERIFICACION COMPLETA DE PASARELAS EN UN SOLO NODO
const resultados = [];

// Configuracion de pasarelas
const pasarelas = [
  {
    nombre: 'Wompi Test',
    tipo: 'sandbox',
    url: 'https://sandbox.wompi.co/v1/merchants/pub_test_fpCO3WW7LRhj0d6RDsmdpktC61ZvoD48',
    method: 'GET'
  },
  {
    nombre: 'Wompi Produccion',
    tipo: 'produccion',
    url: 'https://production.wompi.co/v1/merchants/pub_prod_WmnyfTin0RNwU01LENxf9RuX83TI0pz5',
    method: 'GET'
  },
  {
    nombre: 'MercadoPago Test',
    tipo: 'sandbox',
    url: 'https://api.mercadopago.com/users/me',
    method: 'GET',
    headers: {
      'Authorization': 'Bearer APP_USR-3290830980471268-012213-f968b6be6fc7fd84a74e684f0e7c3d0a-3151906126'
    }
  },
  {
    nombre: 'MercadoPago Produccion',
    tipo: 'produccion',
    url: 'https://api.mercadopago.com/users/me',
    method: 'GET',
    headers: {
      'Authorization': 'Bearer APP_USR-3827499308535843-011614-a3cda5153c8035576ec578c1923260f1-3108446760'
    }
  }
];

// Probar cada pasarela
for (const config of pasarelas) {
  console.log(`Probando: ${config.nombre}...`);

  try {
    const response = await this.helpers.httpRequest({
      method: config.method,
      url: config.url,
      headers: config.headers || {},
      timeout: 10000,
      json: true
    });

    let detalles = {};

    // Extraer info segun pasarela
    if (config.nombre.includes('Wompi')) {
      detalles = {
        merchant_id: response.data?.id || 'N/A',
        name: response.data?.name || 'N/A',
        email: response.data?.email || 'N/A',
        acceptance_token: response.data?.presigned_acceptance?.acceptance_token ? 'Disponible' : 'No disponible'
      };
    } else if (config.nombre.includes('MercadoPago')) {
      detalles = {
        user_id: response.id || 'N/A',
        nickname: response.nickname || 'N/A',
        email: response.email || 'N/A',
        country: response.country_id || 'N/A',
        site: response.site_id || 'N/A'
      };
    }

    resultados.push({
      pasarela: config.nombre,
      tipo: config.tipo,
      status: 'ACTIVA',
      icono: '✅',
      detalles: detalles
    });

    console.log(`✅ ${config.nombre} - OK`);

  } catch (error) {
    resultados.push({
      pasarela: config.nombre,
      tipo: config.tipo,
      status: 'ERROR',
      icono: '❌',
      error_message: error.message,
      error_code: error.statusCode || 'N/A'
    });

    console.log(`❌ ${config.nombre} - ERROR: ${error.message}`);
  }
}

// Generar reporte
let resumenTexto = `
================================================
   REPORTE VERIFICACION PASARELAS DE PAGO
================================================

Fecha: ${new Date().toLocaleString('es-CO')}

`;

resultados.forEach(p => {
  resumenTexto += `
${p.icono} ${p.status} - ${p.pasarela} (${p.tipo})
`;
  if (p.error_message) {
    resumenTexto += `   Error: ${p.error_message}\n`;
    resumenTexto += `   Codigo: ${p.error_code}\n`;
  } else {
    resumenTexto += `   Detalles:\n`;
    Object.entries(p.detalles).forEach(([key, value]) => {
      resumenTexto += `      ${key}: ${value}\n`;
    });
  }
});

const totalActivas = resultados.filter(p => p.status === 'ACTIVA').length;
const totalError = resultados.filter(p => p.status === 'ERROR').length;

resumenTexto += `
================================================
RESUMEN:
  Pasarelas activas: ${totalActivas}/4
  Pasarelas con error: ${totalError}/4
================================================
`;

console.log(resumenTexto);

return [{
  json: {
    timestamp: new Date().toISOString(),
    pasarelas: resultados,
    resumen_texto: resumenTexto,
    total_activas: totalActivas,
    total_error: totalError,
    todas_activas: totalError === 0
  }
}];

// CÓDIGO PARA CONTAR PRODUCTOS REPETIDOS
const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

const productos = [];
const maxPages = 20;
const DELAY_ENTRE_REQUESTS = 500;
const TIMEOUT_POR_REQUEST = 30000;

console.log('🚀 Iniciando carga de productos...');

for (let i = 1; i <= maxPages; i++) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://seze.com.co/wp-json/wc/v3/products',
      auth: {
        username: 'ck_04d98dd4f10c79ef233604e8b587d8515b6d74a9',
        password: 'cs_edacec154f0dfa9c96b19e86b48d69279e26dde5'
      },
      qs: {
        per_page: 100,
        page: i,
        status: 'publish',
        stock_status: 'instock'
      },
      timeout: TIMEOUT_POR_REQUEST,
      retry: {
        limit: 2,
        statusCodes: [429, 500, 502, 503, 504]
      }
    });

    if (!response || response.length === 0) {
      console.log(`✅ Última página procesada: ${i - 1}`);
      break;
    }

    const validos = response
      .filter(p => p.images?.length > 0 && p.stock_status === 'instock')
      .map(p => ({
        id: p.id,
        nombre: p.name,
        nombre_base: p.name.split('-')[0].trim(), // ⭐ Nombre sin variaciones
        sku: p.sku,
        precio: parseFloat(p.price),
        imagen: p.images[0].src,
        categoria: p.categories?.[0]?.name || 'Sin categoría'
      }));

    productos.push(...validos);

    console.log(`📦 Página ${i}: ${validos.length}/${response.length} productos válidos`);

    if (i < maxPages && response.length === 100) {
      await sleep(DELAY_ENTRE_REQUESTS);
    }

  } catch (error) {
    if (error.statusCode === 429) {
      console.warn(`⚠️ Rate limit - Esperando 5s...`);
      await sleep(5000);
      i--;
    } else {
      console.error(`❌ Error página ${i}:`, error.message);
    }
  }
}

// ⭐ CONTAR PRODUCTOS POR NOMBRE BASE
const contadorProductos = {};

productos.forEach(producto => {
  const nombreBase = producto.nombre_base.toLowerCase();

  if (!contadorProductos[nombreBase]) {
    contadorProductos[nombreBase] = {
      nombre: producto.nombre_base,
      cantidad: 0,
      variaciones: [],
      precio_min: producto.precio,
      precio_max: producto.precio,
      imagen: producto.imagen,
      categoria: producto.categoria
    };
  }

  contadorProductos[nombreBase].cantidad++;
  contadorProductos[nombreBase].variaciones.push({
    id: producto.id,
    nombre_completo: producto.nombre,
    sku: producto.sku,
    precio: producto.precio
  });

  // Actualizar precios min/max
  if (producto.precio < contadorProductos[nombreBase].precio_min) {
    contadorProductos[nombreBase].precio_min = producto.precio;
  }
  if (producto.precio > contadorProductos[nombreBase].precio_max) {
    contadorProductos[nombreBase].precio_max = producto.precio;
  }
});

// Ordenar por cantidad (productos con más variaciones primero)
const productosAgrupados = Object.values(contadorProductos)
  .sort((a, b) => b.cantidad - a.cantidad);

// ⭐ REPORTE
console.log(`\n╔════════════════════════════════════════════╗`);
console.log(`║   PRODUCTOS AGRUPADOS POR NOMBRE BASE     ║`);
console.log(`╚════════════════════════════════════════════╝`);
console.log(`\n📦 Total productos individuales: ${productos.length}`);
console.log(`🏷️  Total productos únicos (base): ${productosAgrupados.length}\n`);
console.log(`📊 TOP 10 PRODUCTOS CON MÁS VARIACIONES:\n`);

productosAgrupados.slice(0, 10).forEach((prod, i) => {
  console.log(`   ${i + 1}. ${prod.nombre}: ${prod.cantidad} variaciones`);
  console.log(`      Precio: $${prod.precio_min.toLocaleString('es-CO')} - $${prod.precio_max.toLocaleString('es-CO')}`);
});

return [{
  json: {
    resumen: {
      total_productos_individuales: productos.length,
      total_productos_unicos: productosAgrupados.length,
      fecha: new Date().toISOString()
    },
    productos_agrupados: productosAgrupados,
    todos_los_productos: productos
  }
}];

const response = $input.first().json;

if (response.id) {
  return [{
